class MagixTableDeleter{constructor(){this.modalEl=document.getElementById("delete_modal"),this.confirmBtn=document.getElementById("confirm_delete_btn"),this.currentIds=[],this.modalEl&&this.confirmBtn&&this.init()}init(){document.addEventListener("click",(e=>{const t=e.target.closest('[data-bs-target="#delete_modal"]');if(!t)return;e.preventDefault();const s=t.getAttribute("data-id");if(s)this.currentIds=[s],this.showModal();else{const e=document.querySelectorAll("tbody .table-check:checked");this.currentIds=Array.from(e).map((e=>e.value)),0===this.currentIds.length?MagixToast.warning("Veuillez sélectionner au moins un élément."):this.showModal()}})),this.confirmBtn.addEventListener("click",(()=>this.executeDelete()))}showModal(){bootstrap.Modal.getOrCreateInstance(this.modalEl).show()}async executeDelete(){const e=this.confirmBtn.getAttribute("data-url"),t=new URLSearchParams;this.currentIds.forEach((e=>t.append("ids[]",e)));try{const s=await fetch(e,{method:"POST",headers:{"X-Requested-With":"XMLHttpRequest"},body:t}),a=await s.json();a.success?(bootstrap.Modal.getInstance(this.modalEl).hide(),this.currentIds.forEach((e=>{const t=document.querySelector(`tr[data-id="${e}"]`);t&&(t.classList.add("fade-out"),setTimeout((()=>t.remove()),400))})),MagixToast.success(a.message),this.currentIds=[]):MagixToast.error(a.message)}catch(e){MagixToast.error("Erreur serveur.")}}}document.addEventListener("DOMContentLoaded",(()=>new MagixTableDeleter));